unsigned char CommunicateWithHostByGPRS(void) 
{
unsigned int i;

  for(i=0;i<DataBufferLen;i++)
    if(DataBuffer[i]==2) 
      break;

  BufferLen=0;
  for(;(i<DataBufferLen) && (BufferLen<GlobalBufferLen);i++)
    GlobalBuffer[BufferLen++]=DataBuffer[i];

  ProcessPacket(1);
  
  return(1);
}

//==============================================================================
unsigned int BinSize=0;
unsigned char CommunicateWithHost(void) 
{
unsigned char Byte;

  BufferLen=0;  
  while(USART_GCF(&Byte))
  {
    if(Byte==2)
    {
      GlobalBuffer[BufferLen++]=Byte;
      break;
    }
  }

  while((USART_GCF(&Byte))&&(BufferLen<GlobalBufferLen)) 
    GlobalBuffer[BufferLen++]=Byte;
  
  ProcessPacket(0);
    
  return(1);
}
//=======================================================================
unsigned char CommunicateWithHostByWiFi(void) 
{
unsigned char Byte;

  BufferLen=0;  
  while(WIFI_GCF(&Byte))
  {

    if(Byte==2)
    {
      GlobalBuffer[BufferLen++]=Byte;
      break;
    }
  }

  while((WIFI_GCF(&Byte))&&(BufferLen<GlobalBufferLen)) 
    GlobalBuffer[BufferLen++]=Byte;
  
  ProcessPacket(3);
    
  return(1);
}
